INSERT INTO questions (topic_id, enunciado, alt_a, alt_b, alt_c, alt_d, alt_e, gabarito, tipo, estilo_idecan, dificuldade, comentario_json, tags) VALUES ((SELECT id FROM topics WHERE nome = 'CTB_snt_competencias' LIMIT 1), 'Em operação de fiscalização em via municipal de Campina Grande, agente da STTP lavra auto de infração por estacionamento irregular. O condutor sustenta que apenas a Polícia Militar pode autuar, pois se trata de poder de polícia ostensivo. Com base no CTB e nas competências do Sistema Nacional de Trânsito, assinale a alternativa CORRETA:', 'A autuação por estacionamento em via municipal é atribuição exclusiva da Polícia Militar, cabendo à STTP apenas orientação ao condutor.', 'O órgão executivo de trânsito do Município pode autuar e aplicar penalidades por infrações de circulação, estacionamento e parada.', 'A STTP somente pode autuar se houver delegação expressa do órgão máximo executivo de trânsito da União para cada agente.', 'Infrações de estacionamento em vias urbanas dependem de autorização prévia do CONTRAN, não podendo o Município autuar diretamente.', NULL, 'B', 'caso_pratico', 'pegadinha_pode_deve', 3, '{"o_que_testa":"Competência do órgão executivo de trânsito municipal (STTP) para fiscalizar e autuar infrações de circulação, estacionamento e parada.","fundamento_legal":"CTB, art. 24, VI: compete aos órgãos e entidades executivos de trânsito dos Municípios executar a fiscalização de trânsito em vias terrestres, autuar e aplicar as penalidades de advertência por escrito e multa e as medidas administrativas cabíveis pelas infrações previstas neste Código.","passo_a_passo":["O caso envolve autuação municipal por estacionamento — hipótese típica de competência local.","A) Erra: a PM tem policiamento ostensivo (art. 23), mas não exclusividade para autuar estacionamento urbano.","B) Correta: o art. 24, VI confere ao órgão municipal executar fiscalização e autuar infrações de circulação, estacionamento e parada.","C) Erra: não exige delegação individual por agente; a competência é do órgão municipal.","D) Erra: inventa exigência de autorização prévia do CONTRAN para cada autuação."],"pegadinha":"IDECAN mistura policiamento ostensivo da PM com competência exclusiva de autuação, ignorando o art. 24 do CTB.","macete":"Município autua circulação, estacionamento e parada (art. 24, VI). PM patrulha e atua no ostensivo (art. 23).","estudo_reverso":["CTB art. 21","CTB art. 23","CTB art. 24","CTB art. 280"]}'::jsonb, '{"snt","competencia","sttp","municipal"}'::text[]);